  AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueDst_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> workspaceQueue_;
  AscendC::GlobalTensor<float> xGm_;
